mapper.update:
update `pl_demand_plan_material`
set  status = #{targetStatus}
where 1=1

  and demand_plan_id =#{record.demandPlanId}


  and material_code = #{record.materialCode}


  and logical_plant_no = #{record.logicalPlantNo}


  and status = #{record.status}


  and deleted = #{record.isDelete}

mapper.select:
select

from `pl_demand_plan_material`
    where  1=1

    and demand_plan_id = #{demandPlanId}


    and material_code = #{materialCode}


    and material_desc = #{materialDesc}


    and material_unit = #{materialUnit}


    and logical_plant_no = #{logicalPlantNo}


    and logical_plant_name = #{logicalPlantName}


    and status = #{status}


    and deleted = #{isDelete}


    and tenant_id = #{tenantId}
